1	// --- Rates, fees, and thresholds ---
2	const PROCESSING_FEE = 5;
3	const FIRST_INSURANCE_RATE = 0.1;
4	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
5	const LOYALTY_RATE = 0.2;
6	const LOYALTY_THRESHOLD_YEARS = 2;
7	const CURSE_RATE = 0.5;
8	const HIGH_ENCHANTMENT_RATE = 0.3;
9	const HIGH_ENCHANTMENT_THRESHOLD = 5;
10	const BLOCK_SIZE = 3;
11	const BLOCK_BASE_PREMIUM = 60;
12	
13	// --- Item catalog ---
14	const BASE_PREMIUM: Record<string, number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	  potion: 40,
19	  rune: 25,
20	  moonstone: 25,
21	};
22	
23	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
24	
25	// --- Domain types ---
26	type Customer = { yearsWithMHPCO: number };
27	type Item = { type: string; cursed?: boolean; enchantment?: number };
28	type QuoteStep = { op: "quote"; items: Item[] };
29	type Input = { customer: Customer; steps: QuoteStep[] };
30	type QuoteResult = { premium: number };
31	
32	const countByType = (items: Item[]): Map<string, number> => {
33	  const counts = new Map<string, number>();
34	  for (const item of items) {
35	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
36	  }
37	  return counts;
38	};
39	
40	const basePremiumForType = (type: string, count: number): number => {
41	  const unit = BASE_PREMIUM[type];
42	  if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
43	    return BLOCK_BASE_PREMIUM;
44	  }
45	  return unit * count;
46	};
47	
48	const basePremium = (items: Item[]): number =>
49	  Array.from(countByType(items)).reduce(
50	    (total, [type, count]) => total + basePremiumForType(type, count),
51	    0,
52	  );
53	
54	// MHPCO always rounds premiums in its own favor (up).
55	const roundUpInMHPCOFavor = (amount: number): number => Math.ceil(amount);
56	
57	const isCursed = (item: Item): boolean => item.cursed === true;
58	const isHighlyEnchanted = (item: Item): boolean =>
59	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
60	
61	const itemSurcharge = (item: Item): number => {
62	  const unit = BASE_PREMIUM[item.type];
63	  const curseSurcharge = isCursed(item) ? unit * CURSE_RATE : 0;
64	  const enchantmentSurcharge = isHighlyEnchanted(item)
65	    ? unit * HIGH_ENCHANTMENT_RATE
66	    : 0;
67	  return curseSurcharge + enchantmentSurcharge;
68	};
69	
70	const sumItemSurcharges = (items: Item[]): number =>
71	  items.reduce((total, item) => total + itemSurcharge(item), 0);
72	
73	const isLoyalCustomer = (customer: Customer): boolean =>
74	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
75	
76	const loyaltyDiscount = (base: number, customer: Customer): number =>
77	  isLoyalCustomer(customer) ? base * LOYALTY_RATE : 0;
78	
79	const firstInsuranceSurcharge = (base: number): number =>
80	  base * FIRST_INSURANCE_RATE;
81	
82	const followUpDiscount = (base: number, stepIndex: number): number =>
83	  stepIndex > 0 ? base * FOLLOW_UP_DISCOUNT_RATE : 0;
84	
85	const quotePremium = (step: QuoteStep, customer: Customer, stepIndex: number): QuoteResult => {
86	  const base = basePremium(step.items);
87	  const itemSurcharges = sumItemSurcharges(step.items);
88	  const premium =
89	    base +
90	    itemSurcharges +
91	    firstInsuranceSurcharge(base) -
92	    loyaltyDiscount(base, customer) -
93	    followUpDiscount(base, stepIndex) +
94	    PROCESSING_FEE;
95	  return { premium: roundUpInMHPCOFavor(premium) };
96	};
97	
98	export const run = (input: Input): { results: QuoteResult[] } => ({
99	  results: input.steps.map((step, index) => quotePremium(step, input.customer, index)),
100	});
