const quotePremium = (
  { items }: QuoteStep,
  customer: Customer,
  stepIndex: number,
): QuoteResult => {
  const base = basePremium(items);
  const premium =
    base +
    sumItemSurcharges(items) +
    firstInsuranceSurcharge(base) -
    loyaltyDiscount(base, customer) -
    followUpDiscount(base, stepIndex) +
    PROCESSING_FEE;
  return { premium: roundUpInMHPCOFavor(premium) };
};
